class FfiConverterBoolean: FfiConverter<bool, sbyte> {
    public static FfiConverterBoolean INSTANCE = new FfiConverterBoolean();

    public override bool Lift(sbyte value) {
        return value != 0;
    }

    public override bool Read(BigEndianStream stream) {
        return Lift(stream.ReadSByte());
    }

    public override sbyte Lower(bool value) {
        return value ? (sbyte)1 : (sbyte)0;
    }

    public override int AllocationSize(bool value) {
        return (sbyte)1;
    }

    public override void Write(bool value, BigEndianStream stream) {
        stream.WriteSByte(Lower(value));
    }
}



class FfiConverterString: FfiConverter<string, RustBuffer> {
    public static FfiConverterString INSTANCE = new FfiConverterString();

    // Note: we don't inherit from FfiConverterRustBuffer, because we use a
    // special encoding when lowering/lifting.  We can use `RustBuffer.len` to
    // store our length and avoid writing it out to the buffer.
    public override string Lift(RustBuffer value) {
        try {
            var bytes = value.AsStream().ReadBytes(Convert.ToInt32(value.len));
            return System.Text.Encoding.UTF8.GetString(bytes);
        } finally {
            RustBuffer.Free(value);
        }
    }

    public override string Read(BigEndianStream stream) {
        var length = stream.ReadInt();
        var bytes = stream.ReadBytes(length);
        return System.Text.Encoding.UTF8.GetString(bytes);
    }

    public override RustBuffer Lower(string value) {
        var bytes = System.Text.Encoding.UTF8.GetBytes(value);
        var rbuf = RustBuffer.Alloc(bytes.Length);
        rbuf.AsWriteableStream().WriteBytes(bytes);
        return rbuf;
    }

    // TODO(CS)
    // We aren't sure exactly how many bytes our string will be once it's UTF-8
    // encoded.  Allocate 3 bytes per unicode codepoint which will always be
    // enough.
    public override int AllocationSize(string value) {
        const int sizeForLength = 4;
        var sizeForString = System.Text.Encoding.UTF8.GetByteCount(value);
        return sizeForLength + sizeForString;
    }

    public override void Write(string value, BigEndianStream stream) {
        var bytes = System.Text.Encoding.UTF8.GetBytes(value);
        stream.WriteInt(bytes.Length);
        stream.WriteBytes(bytes);
    }
}




class FfiConverterByteArray: FfiConverterRustBuffer<byte[]> {
    public static FfiConverterByteArray INSTANCE = new FfiConverterByteArray();

    public override byte[] Read(BigEndianStream stream) {
        var length = stream.ReadInt();
        return stream.ReadBytes(length);
    }

    public override int AllocationSize(byte[] value) {
        return 4 + value.Length;
    }

    public override void Write(byte[] value, BigEndianStream stream) {
        stream.WriteInt(value.Length);
        stream.WriteBytes(value);
    }
}



public interface IOtpClient {
    /// <summary>
    /// `account.id` may be "" → assigned. created_at/updated_at always set by core.
    /// </summary>
    /// <exception cref="OtpException"></exception>
    OtpAccount AddAccount(OtpAccount @account);
    /// <exception cref="OtpException"></exception>
    OtpFolder AddFolder(OtpFolder @folder);
    /// <summary>
    /// Accepts otpauth:// (1 account) or otpauth-migration:// (many).
    /// </summary>
    /// <exception cref="OtpException"></exception>
    OtpAccount[] AddFromUri(string @uri);
    /// <exception cref="OtpException"></exception>
    void ChangePassword(string @old, string @new);
    void ClearSyncBackend();
    /// <summary>
    /// Current code for a TOTP account (or HOTP peek without increment).
    /// </summary>
    /// <exception cref="OtpException"></exception>
    OtpCode Code(string @id, long @unixTimeMs);
    /// <summary>
    /// Codes for all (non-deleted) TOTP accounts — for widget timelines.
    /// </summary>
    AccountCode[] CodesAt(long @unixTimeMs);
    /// <summary>
    /// Sets a tombstone (deleted_at = now).
    /// </summary>
    /// <exception cref="OtpException"></exception>
    void DeleteAccount(string @id);
    /// <summary>
    /// Accounts in the folder survive with folder_id cleared.
    /// </summary>
    /// <exception cref="OtpException"></exception>
    void DeleteFolder(string @id);
    /// <summary>
    /// v2 container encrypted under `password` (independent salt/KEK).
    /// </summary>
    /// <exception cref="OtpException"></exception>
    byte[] ExportBackup(string @password);
    OtpAccount? GetAccount(string @id);
    /// <summary>
    /// Returns number of imported (non-skipped) entities.
    /// </summary>
    /// <exception cref="OtpException"></exception>
    uint ImportBackup(byte[] @data, string @password, bool @merge);
    /// <summary>
    /// Legacy v1 .otpbackup import.
    /// </summary>
    /// <exception cref="OtpException"></exception>
    uint ImportBackupV1(byte[] @data, string @password, bool @merge);
    OtpAccount[] ListAccounts();
    OtpFolder[] ListFolders();
    /// <summary>
    /// HOTP: increments the counter and persists, then returns the code.
    /// </summary>
    /// <exception cref="OtpException"></exception>
    OtpCode NextHotp(string @id);
    /// <summary>
    /// Re-read the vault file (app ↔ widget coherence).
    /// </summary>
    /// <exception cref="OtpException"></exception>
    void Reload();
    void SetSyncBackend(SyncBackend @backend);
    /// <exception cref="OtpException"></exception>
    SyncOutcome Sync(long @unixTimeMs);
    /// <exception cref="OtpException"></exception>
    OtpAccount UpdateAccount(OtpAccount @account);
    /// <exception cref="OtpException"></exception>
    OtpFolder UpdateFolder(OtpFolder @folder);
    /// <summary>
    /// The raw 32-byte vault master key, for the platform keystore.
    /// </summary>
    byte[] VaultKey();
}
