        }
    }
    
    
    public class WrongPassword : OtpException {
        public WrongPassword() : base() {}
    }
    
    
    
    public class WrongKey : OtpException {
        public WrongKey() : base() {}
    }
    
    
    
    public class Corrupt : OtpException {
        // Members
