class FfiConverterTypeOtpError : FfiConverterRustBuffer<OtpException>, CallStatusErrorHandler<OtpException> {
    public static FfiConverterTypeOtpError INSTANCE = new FfiConverterTypeOtpError();

    public override OtpException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new OtpException.InvalidSecret(
                    FfiConverterString.INSTANCE.Read(stream));
            case 2:
                return new OtpException.InvalidUri(
                    FfiConverterString.INSTANCE.Read(stream));
            case 3:
                return new OtpException.InvalidParameter(
                    FfiConverterString.INSTANCE.Read(stream));
            case 4:
                return new OtpException.WrongPassword();
            case 5:
                return new OtpException.WrongKey();
            case 6:
                return new OtpException.Corrupt(
                    FfiConverterString.INSTANCE.Read(stream));
            case 7:
                return new OtpException.Io(
                    FfiConverterString.INSTANCE.Read(stream));
            case 8:
                return new OtpException.Crypto(
                    FfiConverterString.INSTANCE.Read(stream));
            case 9:
                return new OtpException.NotFound(
                    FfiConverterString.INSTANCE.Read(stream));
            case 10:
                return new OtpException.NotConfigured();
            case 11:
                return new OtpException.Network(
                    FfiConverterString.INSTANCE.Read(stream));
            case 12:
                return new OtpException.Auth(
                    FfiConverterString.INSTANCE.Read(stream));
            case 13:
                return new OtpException.Conflict();
            case 14:
                return new OtpException.Backend(
                    FfiConverterString.INSTANCE.Read(stream));
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeOtpError.Read()", value));
        }
    }

    public override int AllocationSize(OtpException value) {
        switch (value) {

            case OtpException.InvalidSecret variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case OtpException.InvalidUri variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case OtpException.InvalidParameter variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case OtpException.WrongPassword variant_value:
                return 4;

            case OtpException.WrongKey variant_value:
                return 4;

            case OtpException.Corrupt variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case OtpException.Io variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case OtpException.Crypto variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case OtpException.NotFound variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@id);

            case OtpException.NotConfigured variant_value:
                return 4;

            case OtpException.Network variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case OtpException.Auth variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case OtpException.Conflict variant_value:
                return 4;

            case OtpException.Backend variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeOtpError.AllocationSize()", value));
        }
    }

    public override void Write(OtpException value, BigEndianStream stream) {
        switch (value) {
            case OtpException.InvalidSecret variant_value:
                stream.WriteInt(1);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case OtpException.InvalidUri variant_value:
                stream.WriteInt(2);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case OtpException.InvalidParameter variant_value:
                stream.WriteInt(3);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case OtpException.WrongPassword variant_value:
                stream.WriteInt(4);
                break;
            case OtpException.WrongKey variant_value:
                stream.WriteInt(5);
                break;
            case OtpException.Corrupt variant_value:
                stream.WriteInt(6);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case OtpException.Io variant_value:
                stream.WriteInt(7);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case OtpException.Crypto variant_value:
                stream.WriteInt(8);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case OtpException.NotFound variant_value:
                stream.WriteInt(9);
                FfiConverterString.INSTANCE.Write(variant_value.@id, stream);
                break;
            case OtpException.NotConfigured variant_value:
                stream.WriteInt(10);
                break;
            case OtpException.Network variant_value:
                stream.WriteInt(11);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case OtpException.Auth variant_value:
                stream.WriteInt(12);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case OtpException.Conflict variant_value:
                stream.WriteInt(13);
                break;
            case OtpException.Backend variant_value:
                stream.WriteInt(14);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeOtpError.Write()", value));
        }
    }
}





