class FfiConverterSequenceTypeAccountCode: FfiConverterRustBuffer<AccountCode[]> {
    public static FfiConverterSequenceTypeAccountCode INSTANCE = new FfiConverterSequenceTypeAccountCode();

    public override AccountCode[]  Read(BigEndianStream stream) {
        var length = stream.ReadInt();
        if (length == 0) {
            return [];
        }

        var result = new AccountCode[(length)];
        var readFn = FfiConverterTypeAccountCode.INSTANCE.Read;
        for (int i = 0; i < length; i++) {
            result[i] = readFn(stream);
        }
        return result;
    }

    public override int AllocationSize(AccountCode[]  value) {
        var sizeForLength = 4;

        // details/1-empty-list-as-default-method-parameter.md
        if (value == null) {
            return sizeForLength;
        }

        var allocationSizeFn = FfiConverterTypeAccountCode.INSTANCE.AllocationSize;
        var sizeForItems = value.Sum(item => allocationSizeFn(item));
        return sizeForLength + sizeForItems;
    }

    public override void Write(AccountCode[] value, BigEndianStream stream) {
        // details/1-empty-list-as-default-method-parameter.md
        if (value == null) {
            stream.WriteInt(0);
            return;
        }

        stream.WriteInt(value.Length);
        var writerFn = FfiConverterTypeAccountCode.INSTANCE.Write;
        value.ForEach(item => writerFn(item, stream));
    }
}




